VALUES
  ('aboriginal-444ca548-moex-00196', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民族語言發展法之規定，下列敘述何者錯誤？', '["原住民山地鄉、平地鄉之鄉公所，可以以該地區之原住民族語言書寫公文", "花蓮火車站可以使用阿美族、太魯閣族語進行播音", "為因應原住民學生學習的需求，花蓮的國民中小學可以以阿美族語或是太魯閣族語進行教學", "原住民至法院出庭陳述意見時，可以以原民族語言陳述意見，但需自行聘請通譯傳譯之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00197', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民族基本法，下列敘述何者錯誤？', '["原住民得在原住民族地區從事獵捕野生動物、採集野生植物、礦物、土石等營利行為", "當政府或私人於原住民族土地從事土地開發時，原住民族或部落得拒絕之", "當政府於原住民族地區劃設國家公園、國家級風景特定區、林業區、生態保育區時，原住民族得拒 絕之", "當政府欲於原住民族地區內存放有害物質時，原住民族得拒絕之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00198', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民族基本法，下列名詞定義，何者錯誤？', '["原住民族地區，係指原住民傳統居住，具有原住民族歷史淵源及文化特色，經中央原住民族主管機 關報請行政院核定之地區", "部落，係指原住民於原住民族地區一定區域內，依其傳統規範共同生活結合而成之團體，且經中央 原住民族主管機關核定者", "原住民族土地，係指原住民保留地", "原住民族，係指阿美族、泰雅族、排灣族、布農族、卑南族、魯凱族、鄒族、賽夏族、雅美族、邵 族、噶瑪蘭族、太魯閣族及其他自認為原住民族並經中央原住民族主管機關報請行政院核定之民族"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00199', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民身分法，下列何種情形不是原住民得申請喪失原住民身分之情形？', '["與非原住民結婚", "為非原住民收養", "未滿7歲之原住民為非原住民收養", "年滿20歲，自願拋棄之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00200', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民族基本法第21條之規定，政府或私人於原住民族土地或部落及其周邊一定範圍內之公有 土地從事某些事情時，應諮商並取得原住民族或部落同意或參與，下列那一個選項不包括之？', '["土地開發", "資源利用", "學術研究", "劃設生態保育區"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00201', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民保留地開發管理辦法，原住民申請無償取得原住民保留地所有權，土地面積最高限額，何 者正確？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區，並供農作、養殖 或畜牧使用之土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人一公頃", "依法得為建築使用之土地，每戶一公頃", "其他用地，每戶一公頃"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00202', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '有關於原住民族傳統智慧創作保護條例之內容，下列敘述何者錯誤？', '["原住民族的智慧創作，必須要經原住民族委員會認定並登記，才會受到保護", "經認定並登記的原住民族智慧創作專用權，包括智慧創作財產權及智慧創作人格權", "學校可以基於教育的目的，使用已公開發表之智慧創作", "原住民個人使用所屬民族、部落或全部原住民族之智慧創作，其收益屬全體原住民族"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00203', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '依據原住民保留地開發管理辦法，原住民依法取得之耕作權或地上權登記後繼續自行經營或自用滿幾 年後，可向當地登記機關申請辦理所有權移轉登記？', '["1年", "3年", "5年", "申請年限限制已刪除，原住民可直接申請無償取得原住民保留地所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00204', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '關於原住民族之傳統智慧創作，下列何者非原住民族傳統智慧創作保護條例中所稱之智慧創作？', '["阿美族的老人飲酒歌", "排灣族的勇士舞", "太魯閣族的竹筒飯", "雅美族的傳統圖騰-船眼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL),
  ('aboriginal-444ca548-moex-00205', 'aboriginal-444ca548', 'aboriginal-444ca548-moex-111-6ed013db', 'sub-aboriginal-444ca548-06', NULL, 'single_choice', '2021年10月8日，大法官公布第810號解釋，宣布原住民族工作權保障法第24條第2項之規定部 分違憲，其主要依據為何？', '["該法條侵害投標廠商之平等權", "該法條侵害投標廠商之營業自由", "該法條侵害投標廠商之財產權", "該法條以劃一的方式計算代金金額，在特殊個案情形，難免沒有辦法兼顧實質正義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "609", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "農業行政"}'::jsonb, NULL)
